example.code:
from openai import OpenAI
client = OpenAI()

def get_embedding(text: str, model: str = "text-embedding-3-large") -> list[float]:
    return client.embeddings.create(input=text, model=model).data[0].embedding

def get_embeddings_batch(
    texts: list[str],
    model: str = "text-embedding-3-large",
    batch_size: int = 2048,
) -> list[list[float]]:
    all_embeddings: list[list[float]] = []
    for i in range(0, len(texts), batch_size):
        batch = texts[i : i + batch_size]
        response = client.embeddings.create(input=batch, model=model)
        sorted_data = sorted(response.data, key=lambda x: x.index)
        all_embeddings.extend([e.embedding for e in sorted_data])
    return all_embeddings

def get_embedding_reduced(text: str, dimensions: int = 256) -> list[float]:
    """Matryoshka reduction — text-embedding-3 models only."""
    return client.embeddings.create(
        input=text, model="text-embedding-3-large", dimensions=dimensions
    ).data[0].embedding

from mistralai import Mistral
client = Mistral(api_key="YOUR_API_KEY")

def get_mistral_embedding(text: str) -> list[float]:
    return client.embeddings.create(model="mistral-embed", inputs=[text]).data[0].embedding

def get_mistral_embeddings_batch(texts: list[str]) -> list[list[float]]:
    return [e.embedding for e in client.embeddings.create(model="mistral-embed", inputs=texts).data]

import cohere
co = cohere.Client("YOUR_API_KEY")

def get_cohere_embeddings(
    texts: list[str],
    input_type: str = "search_document",  # or "search_query"
) -> list[list[float]]:
    return co.embed(
        texts=texts,
        model="embed-english-v3.0",
        input_type=input_type,
        truncate="END",
    ).embeddings

import torch
from sentence_transformers import SentenceTransformer

device = "cuda" if torch.cuda.is_available() else "cpu"
model = SentenceTransformer("BAAI/bge-large-en-v1.5", device=device)

def get_local_embeddings(texts: list[str], batch_size: int = 32):
    return model.encode(
        texts, batch_size=batch_size, normalize_embeddings=True, convert_to_numpy=True
    )

# BGE-M3: dense + sparse for hybrid search
from FlagEmbedding import BGEM3FlagModel
bgem3 = BGEM3FlagModel("BAAI/bge-m3", use_fp16=True)

def get_bgem3(texts: list[str]) -> dict:
    return bgem3.encode(texts, return_dense=True, return_sparse=True)
# result["dense_vecs"] → np.ndarray
# result["lexical_weights"] → list[dict[str, float]]
